SELECT
oc.*
FROM
t_oil_card oc

    LEFT JOIN t_employee receiveUser ON receiveUser.employee_id = oc.receive_user_id
    LEFT JOIN t_vehicle v ON v.vehicle_id = oc.use_vehicle_id
    LEFT JOIN t_driver d ON d.driver_id = oc.use_driver_id

where
    oc.deleted_flag = #{queryForm.deletedFlag}

        AND (INSTR(oc.oil_card_no,#{queryForm.keyWords})
        or INSTR(oc.create_user_name,#{queryForm.keyWords})
        or INSTR(d.driver_name,#{queryForm.keyWords})
        or INSTR(v.vehicle_number,#{queryForm.keyWords})
        )


        AND oc.master_oil_card_id = #{queryForm.masterOilCardId}


        AND oc.disabled_flag = #{queryForm.disabledFlag}


        AND oc.type = #{queryForm.type}


        AND oc.fuel_type = #{queryForm.fuelType}


        AND oc.enterprise_id = #{queryForm.enterpriseId}


        AND oc.enterprise_id in

            #{item}



        and DATE_FORMAT(oc.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        and DATE_FORMAT(oc.create_time, '%Y-%m-%d') <= #{queryForm.endTime}

group by oc.oil_card_id

    ORDER BY oc.create_time DESC

SELECT
IFNULL(SUM(recordList.amount ),0)
FROM (
    SELECT
    ocbr.change_balance as amount
    FROM t_oil_card_balance_record ocbr
    LEFT JOIN t_oil_card oc on oc.oil_card_id = ocbr.oil_card_id

        LEFT JOIN t_employee receiveUser ON receiveUser.employee_id = oc.receive_user_id
        LEFT JOIN t_vehicle v ON v.vehicle_id = oc.use_vehicle_id
        LEFT JOIN t_driver d ON d.driver_id = oc.use_driver_id

    where
    oc.deleted_flag = #{queryForm.deletedFlag}

        AND (INSTR(oc.oil_card_no,#{queryForm.keyWords})
        or INSTR(oc.create_user_name,#{queryForm.keyWords})
        or INSTR(d.driver_name,#{queryForm.keyWords})
        or INSTR(v.vehicle_number,#{queryForm.keyWords})
        )


        AND oc.master_oil_card_id = #{queryForm.masterOilCardId}


        AND oc.disabled_flag = #{queryForm.disabledFlag}


        AND oc.type = #{queryForm.type}


        AND oc.fuel_type = #{queryForm.fuelType}


        AND oc.enterprise_id = #{queryForm.enterpriseId}


        and DATE_FORMAT(oc.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        and DATE_FORMAT(oc.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


        and ocbr.record_type = #{queryForm.recordType}


        and DATE_FORMAT(transaction_time, '%Y-%m-%d') >= #{queryForm.balanceRecordStartTime}


        and DATE_FORMAT(transaction_time, '%Y-%m-%d') <= #{queryForm.balanceRecordEndTime}

    group by ocbr.balance_record_id
) as recordList

select * from t_oil_card where oil_card_no = #{oilCardNo} and deleted_flag = #{deletedFlag}

    and oil_card_id not in

        #{item}

SELECT oc.* FROM t_oil_card oc where deleted_flag = #{deletedFlag} AND type = #{type} and oc.enterprise_id not in
#{item}
GROUP BY oc.oil_card_id

select * from t_oil_card where deleted_flag = #{deletedFlag}
and oil_card_no in

    #{item}


    and master_oil_card_id = #{masterOilCardId}


    and master_oil_card_id != #{excludeMasterOilCardId}

select * from t_oil_card where deleted_flag = #{deletedFlag}
and disabled_flag = #{disabledFlag}
and type = #{type}
and (use_vehicle_id = #{vehicleId} or fixed_point_flag = #{fixedPointFlag})

SELECT fuel_type
FROM t_oil_card
WHERE oil_card_id = #{oilCardId}

